import React, { useEffect, useRef } from "react";
import "./HowItWorks.css";

function useReveal() {
    useEffect(() => {
        const els = document.querySelectorAll(".r,.r-l,.r-r");
        const io = new IntersectionObserver(
            es => es.forEach(e => { if (e.isIntersecting) { e.target.classList.add("in"); io.unobserve(e.target); } }),
            { threshold: 0.12 }
        );
        els.forEach(el => io.observe(el));
        return () => io.disconnect();
    });
}

const steps = [
    {
        num:"01", tag:"Step One", title:"Upload to IPFS",
        headline:"CONTENT-ADDRESSED",
        desc:"Your PDF is uploaded to the InterPlanetary File System via Pinata. IPFS stores files by content — it runs your file through SHA-256 and returns a Content Identifier (CID): a cryptographic fingerprint of every single byte. Any modification changes the CID entirely.",
        details:[
            "SHA-256 cryptographic hashing of all file bytes",
            "Pinata pinning ensures global IPFS availability",
            "Even 1 byte change produces a completely different CID",
            "CID is mathematically unique — impossible to fake",
        ],
        code:"const cid = await uploadToPinata(file);\n// → bafybeigdyrzt5sfp7...",
        img:"https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=1100&q=80",
        accent:"#b8922a",
    },
    {
        num:"02", tag:"Step Two", title:"Register On-Chain",
        headline:"IMMUTABLE",
        desc:"Your CID, Ethereum wallet address, and a network-consensus timestamp are written into the PaperRegistry smart contract on Polygon. The contract permanently rejects any future attempt to register the same CID — making you the irrefutable first. No admin, no backdoor.",
        details:[
            "msg.sender cryptographically verifies your identity",
            "block.timestamp set by Polygon network consensus",
            "Duplicate CIDs are rejected with 'Paper already registered'",
            "No owner, no admin — the code is the only rule",
        ],
        code:"await registry.submitPaper(cid);\n// Confirmed · Block #1,284,920",
        img:"https://images.unsplash.com/photo-1639322537228-f710d846310a?w=1100&q=80",
        accent:"#3d7fff",
    },
    {
        num:"03", tag:"Step Three", title:"Verify Anywhere",
        headline:"TRUSTLESS",
        desc:"Anyone in the world can call getPaper() with a CID. The blockchain returns the author address, block timestamp, and full precedence status — instantly, permissionlessly, without any trusted third party. This is what trustless means: the math is the authority.",
        details:[
            "getPaper() is a read-only view function — costs zero gas",
            "Anyone can call it, no wallet or account needed",
            "Returns author address, timestamp, and CID existence",
            "Verifiable as long as the Polygon blockchain exists",
        ],
        code:"const [cid, author, ts, exists]\n  = await registry.getPaper(cid);",
        img:"https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=1100&q=80",
        accent:"#1a6b5a",
    },
];

function Step({ step, i }) {
    const ref = useRef(null);
    useEffect(() => {
        const io = new IntersectionObserver(
            ([e]) => { if (e.isIntersecting) { ref.current?.classList.add("hiw-step--in"); io.unobserve(ref.current); } },
            { threshold: 0.12 }
        );
        if (ref.current) io.observe(ref.current);
        return () => io.disconnect();
    }, []);
    const even = i % 2 === 1;
    return (
        <div className={`hiw-step ${even ? "hiw-step--flip" : ""}`} ref={ref}>
            <div className="hiw-step__img-col">
                <img src={step.img} alt={step.title} className="hiw-step__img" loading="lazy" />
                <div className="hiw-step__img-ov" />
                <div className="hiw-step__img-num">{step.num}</div>
                <div className="hiw-step__img-word" style={{color: `${step.accent}14`}}>{step.headline}</div>
                <div className="hiw-step__code-ov">
                    <pre className="hiw-step__code">{step.code}</pre>
                </div>
            </div>
            <div className="hiw-step__text-col" style={{"--a": step.accent}}>
                <div className="hiw-step__headline">{step.headline}</div>
                <div className="hiw-step__tag">{step.tag} · {step.num}</div>
                <h3 className="hiw-step__title">{step.title}</h3>
                <p className="hiw-step__desc">{step.desc}</p>
                <ul className="hiw-step__list">
                    {step.details.map(d => (
                        <li key={d} className="hiw-step__item">
                            <span className="hiw-step__bullet"/>
                            {d}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
}

export default function HowItWorks({ navigate }) {
    useReveal();
    return (
        <div className="hiw page-enter">

            {/* ── Hero banner ── */}
            <section className="hiw-hero">
                <div className="hiw-hero__bg"/>
                <div className="hiw-hero__ov"/>
                <div className="hiw-hero__grid tech-grid-bg"/>
                <div className="hiw-hero__bleed">HOW</div>
                <div className="hiw-hero__content">
                    <div className="eyebrow r">The Process</div>
                    <h1 className="hiw-hero__h1 r">
                        Three steps.<br /><em className="gold-text">Permanent proof.</em>
                    </h1>
                    <p className="hiw-hero__sub r">
                        From raw PDF to immutable blockchain record — here's exactly what happens
                        at every stage of Proof of Precedence.
                    </p>
                </div>
                <div className="hiw-hero__stats">
                    {[{v:"3",l:"Steps"},{v:"SHA-256",l:"Hashing"},{v:"EVM",l:"Execution"},{v:"0 Gas",l:"To Verify"}].map(({v,l})=>(
                        <div className="hiw-hero__stat" key={l}>
                            <div className="hiw-hero__stat-v">{v}</div>
                            <div className="hiw-hero__stat-l">{l}</div>
                        </div>
                    ))}
                </div>
            </section>

            {/* ── Steps ── */}
            <div className="hiw-steps">
                {steps.map((s,i) => <Step key={s.num} step={s} i={i} />)}
            </div>

            {/* ── Flow diagram ── */}
            <section className="hiw-flow">
                <div className="hiw-flow__bleed">FLOW</div>
                <div className="hiw-flow__inner">
                    <div className="eyebrow r">The Complete Flow</div>
                    <h2 className="section-h hiw-flow__h2 r">End-to-end in one view.</h2>
                    <div className="hiw-flow__diagram r">
                        {[
                            {icon:"📄", label:"Your PDF", sub:"Any research paper"},
                            {icon:"→", arrow:true},
                            {icon:"🌐", label:"IPFS", sub:"SHA-256 → CID"},
                            {icon:"→", arrow:true},
                            {icon:"⛓", label:"Blockchain", sub:"CID + Wallet + Timestamp"},
                            {icon:"→", arrow:true},
                            {icon:"✅", label:"Proof", sub:"Public · Permanent · Verified"},
                        ].map((item,i) => item.arrow ? (
                            <div className="hiw-flow__arrow" key={i}>→</div>
                        ) : (
                            <div className="hiw-flow__node" key={i}>
                                <div className="hiw-flow__node-icon">{item.icon}</div>
                                <div className="hiw-flow__node-label">{item.label}</div>
                                <div className="hiw-flow__node-sub">{item.sub}</div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* ── CTA ── */}
            <section className="hiw-cta">
                <div className="hiw-cta__inner r">
                    <h2 className="section-h hiw-cta__h2">Ready to register your paper?</h2>
                    <div className="hiw-cta__btns">
                        <button className="btn btn-gold" onClick={() => { navigate("app"); window.scrollTo(0,0); }}>
                            <span>Launch the App →</span>
                        </button>
                        <button className="btn btn-ghost" onClick={() => { navigate("tech"); window.scrollTo(0,0); }}>
                            Explore the Technology
                        </button>
                    </div>
                </div>
            </section>

        </div>
    );
}
